"use strict";(self.webpackChunkengineering_knowledge_base=self.webpackChunkengineering_knowledge_base||[]).push([[98550],{18045(e){e.exports=JSON.parse('{"tag":{"label":"domain-1","permalink":"/tags/domain-1","allTagsPath":"/tags","count":12,"items":[{"id":"technical-knowledge/aws/api-gateway/index","title":"Amazon API Gateway","description":"API Gateway for DVA-C02. REST API vs HTTP API vs WebSocket API, integration types, authorizers (Cognito, Lambda), deployment stages, caching, throttling, CORS, canary deployments, and usage plans.\\n","permalink":"/technical-knowledge/aws/api-gateway/"},{"id":"technical-knowledge/aws/dynamodb/index","title":"Amazon DynamoDB","description":"DynamoDB mastery for DVA-C02. Covers partition keys, sort keys, GSI vs LSI, read/write capacity modes, DynamoDB Streams, DAX, TTL, transactions, and the most common exam scenarios and anti-patterns.\\n","permalink":"/technical-knowledge/aws/dynamodb/"},{"id":"technical-knowledge/aws/elasticache/index","title":"Amazon ElastiCache","description":"Amazon ElastiCache for DVA-C02. Redis vs Memcached comparison, caching strategies (lazy loading, write-through, session store), cluster modes, Multi-AZ, and common exam patterns.\\n","permalink":"/technical-knowledge/aws/elasticache/"},{"id":"technical-knowledge/aws/messaging/kinesis","title":"Amazon Kinesis","description":"Kinesis Data Streams vs Kinesis Data Firehose vs Kinesis Data Analytics. Shards, partition keys, sequence numbers, Enhanced Fan-Out, Lambda ESM, and when to use Kinesis vs SQS.\\n","permalink":"/technical-knowledge/aws/messaging/kinesis"},{"id":"technical-knowledge/aws/s3/index","title":"Amazon S3","description":"Amazon S3 for DVA-C02. Storage classes, versioning, lifecycle policies, presigned URLs, encryption (SSE-S3, SSE-KMS, SSE-C), CORS, event notifications, multipart uploads, and cross-region replication.\\n","permalink":"/technical-knowledge/aws/s3/"},{"id":"technical-knowledge/aws/messaging/sns","title":"Amazon SNS","description":"Amazon SNS for DVA-C02. Topics, subscriptions, fan-out pattern with SQS, message filtering, SNS FIFO, mobile push notifications, and the difference between SNS and SQS.\\n","permalink":"/technical-knowledge/aws/messaging/sns"},{"id":"technical-knowledge/aws/messaging/sqs","title":"Amazon SQS","description":"Amazon SQS for DVA-C02 \u2014 standard vs FIFO queues, visibility timeout, message retention, DLQ, long polling, delay queues, and Lambda integration via Event Source Mapping. Key exam patterns covered.\\n","permalink":"/technical-knowledge/aws/messaging/sqs"},{"id":"technical-knowledge/aws/lambda/index","title":"AWS Lambda","description":"Comprehensive Lambda study guide for DVA-C02. Covers invocation types, concurrency, cold starts, event source mappings, layers, container images, environment variables, VPC integration, destinations, and Java handler patterns.\\n","permalink":"/technical-knowledge/aws/lambda/"},{"id":"technical-knowledge/aws/step-functions/index","title":"AWS Step Functions","description":"AWS Step Functions for DVA-C02. Standard vs Express workflows, state types, error handling, Wait for Callback, Map state for parallel processing, and integration with Lambda, SQS, DynamoDB, and API Gateway.\\n","permalink":"/technical-knowledge/aws/step-functions/"},{"id":"technical-knowledge/aws/dynamodb/advanced","title":"DynamoDB Advanced \u2014 Streams, PartiQL & Enhanced Client","description":"Advanced DynamoDB topics for DVA-C02. DynamoDB Streams with Lambda, PartiQL, Enhanced Client for Java, optimistic locking, single-table design patterns, and Write Sharding.\\n","permalink":"/technical-knowledge/aws/dynamodb/advanced"},{"id":"technical-knowledge/aws/containers/ecs-ecr","title":"ECS & ECR \u2014 Containers on AWS","description":"Amazon ECS and ECR for DVA-C02. EC2 vs Fargate launch types, task definitions, services, IAM roles for tasks, service auto scaling, ECR image management, and integration with CodePipeline.\\n","permalink":"/technical-knowledge/aws/containers/ecs-ecr"},{"id":"technical-knowledge/aws/s3/advanced","title":"S3 Advanced \u2014 Replication, Transfer Acceleration & Object Lambda","description":"Advanced S3 topics for DVA-C02. Cross-Region Replication, Same-Region Replication, S3 Transfer Acceleration, Object Lambda, MFA Delete, S3 Select, Requester Pays, and event processing patterns.\\n","permalink":"/technical-knowledge/aws/s3/advanced"}],"unlisted":false}}')}}]);